/* eslint-disable max-len */
import React from 'react';
import PropTypes from 'prop-types';
import Close12 from '@andes/icons/Close12';
import Close20 from '@andes/icons/Close20';

/**
 * @typedef {Object} ClearButtonProps
 * @prop {string} [`aria-label`]
 * @prop {string} namespace
 * @prop {() => void} onClick
 * @prop {string} [size]
 */

/** @type {React.FunctionComponent<ClearButtonProps>} */
const ClearButton = ({ namespace, onClick, 'aria-label': ariaLabel = '', size = 'large' }) => (
  <button
    aria-label={ariaLabel}
    className={`${namespace}__clear-icon`}
    onClick={onClick}
    onMouseDown={e => e.preventDefault()}
    type="button"
  >
    {size === 'large' ? <Close20 color="currentColor" /> : <Close12 color="currentColor" />}
  </button>
);

ClearButton.propTypes = {
  'aria-label': PropTypes.string,
  namespace: PropTypes.string.isRequired,
  onClick: PropTypes.func.isRequired,
  size: PropTypes.string,
};

export default ClearButton;
