import React, { useRef } from 'react';
import PropTypes from 'prop-types';
import classNames from 'classnames';
import { useFocusRing } from '@react-aria/focus';
import { useId, useAndesContext } from '@andes/context';
import enTranslations from '../../translations/en/messages.json';
import zhCnTranslations from '../../translations/zh-CN/messages.json';
import esArTranslations from '../../translations/es-AR/messages.json';
import ptBrTranslations from '../../translations/pt-BR/messages.json';
import handlers from '../scripts/handlers';
import transformToKebabCase from '@andes/common/build/utils/transformToKebabCase';
import { checkChildrenProp, checkLabelProp } from '../constants/warnings/shared';
import { DropdownItem, DropdownStandalone } from '@andes/dropdown';
import TextField from './TextField';
import { Helper } from '@andes/form';
import { computeModifier } from '../utils';
import { useThemeContext } from '@andes/themes';

import { formControlNamespace, splitButtonNamespace } from '../constants';

/** @type {typeof import('../..').SplitTextfield} */
const SplitTextfield = ({ ref, ...props }) => {
  const {
    autoFocus = false,
    children,
    className,
    defaultSelection = 0,
    defaultValue,
    disabled = false,
    helper,
    inputProps,
    id,
    label,
    list,
    modifier,
    placeholder,
    onBlur,
    onChange,
    onDropdownOpen,
    onFocus,
    splitIcon,
    splitLabel,
    splitPosition = 'left',
    srLabel,
    value,
    ...other
  } = /** @type {import('../..').SplitTextfieldProps} */ (props);

  const getDefaultValue = () => (list?.content[defaultSelection]?.title);

  /** @type {React.RefObject<HTMLDivElement | null>} */
  const ownContainerRef = useRef(null);

  /** @type {React.RefObject<HTMLDivElement | null>} */
  const containerRef = /** @type {React.RefObject<HTMLDivElement | null>} */(ref) || ownContainerRef;

  /**
   * This is a ref to the TextField component
   * @type {React.RefObject<any>}
   */
  const fieldRef = useRef(undefined);

  const componentId = useId(id);

  const { isFocusVisible, focusProps } = useFocusRing({ isTextInput: true });

  const isReadonly = modifier === 'readonly';

  const { getThemedComponentClasses, themeHash } = useThemeContext();

  const { i18n } = useAndesContext('@andes/textfield',
    { en: enTranslations, 'es-AR': esArTranslations, 'pt-BR': ptBrTranslations, 'zh-CN': zhCnTranslations });

  const containerClassNames = classNames(formControlNamespace, className,
    `${formControlNamespace}--textfield`,
    `${formControlNamespace}--split`,
    {
      [`${formControlNamespace}--split__embedded`]: children,
      [`${formControlNamespace}--${modifier}`]: modifier,
      [`${formControlNamespace}--focused`]: autoFocus,
      [`${formControlNamespace}--disabled`]: disabled,
    },
    getThemedComponentClasses?.('textfield'),
  );

  const splitControlClassNames = classNames(`${formControlNamespace}__control`, {
    [`${formControlNamespace}__control--visible-focused`]: isFocusVisible,
  });

  const splitButtonClassNames = classNames(splitButtonNamespace, {
    [`${splitButtonNamespace}--right`]: splitPosition === 'right',
    [`${splitButtonNamespace}--readonly`]: isReadonly,
  });

  const fieldClassNames = classNames(`${formControlNamespace}__field ${formControlNamespace}__split-field`, {
    [`${formControlNamespace}__split-field--readonly`]: isReadonly,
  });

  const iconClassNames = classNames(`${splitButtonNamespace}-content--icon`, {
    [`${splitButtonNamespace}-content--icon-disabled`]: disabled,
  });

  const splitItemClassNames = `${formControlNamespace}--split-item`;

  /** @type {import('@andes/dropdown').DropdownCommonProps['onChange']} */
  const customOnChange = (_, itemValue) => {
    if (!list) return;

    const { content, onClick } = list;

    if (typeof onClick === 'function' && itemValue) {
      // @ts-expect-error: The selected item will always exist
      onClick(content.find(({ title }) => title === itemValue));
    }
  };

  /** @param {React.FocusEvent<HTMLInputElement | HTMLTextAreaElement>} event */
  const customOnBlur = (event) => {
    handlers.onBlur(containerRef.current, fieldRef.current?.field.value);
    if (typeof focusProps.onBlur === 'function') focusProps.onBlur(event);

    if (typeof onBlur === 'function') onBlur(event);
  };

  /** @param {React.FocusEvent<HTMLInputElement | HTMLTextAreaElement>} event */
  const customOnFocus = (event) => {
    handlers.onFocus(containerRef.current);
    if (typeof focusProps.onFocus === 'function') focusProps.onFocus(event);

    if (typeof onFocus === 'function') onFocus(event);
  };

  /** @param {React.ReactNode} triggerContent */
  const renderCustomTrigger = (triggerContent) => {
    let adaptedTriggerContent = triggerContent;

    if (splitLabel) adaptedTriggerContent = splitLabel;

    if (splitIcon) {
      adaptedTriggerContent = (
        <>
          <span className={iconClassNames}>{splitIcon}</span>
          {adaptedTriggerContent}
        </>
      );
    }

    return adaptedTriggerContent;
  };

  const fieldProps = {
    ...other,
    inputProps: {
      'aria-describedby': helper ? `${componentId}-message` : undefined,
      ...inputProps,
    },
    'aria-invalid': modifier === 'error',
    'aria-labelledby': `${componentId}-dropdown-trigger`,
    srLabel: srLabel || label,
    className: fieldClassNames,
    children,
    defaultValue,
    disabled,
    id: componentId,
    modifier: modifier !== 'error' ? modifier : undefined,
    onBlur: customOnBlur,
    onChange,
    onFocus: customOnFocus,
    placeholder,
    ref: fieldRef,
    value,
    i18n,
  };

  return (
    <div className={containerClassNames} ref={containerRef} {...themeHash} data-andes-split-textfield>
      {label && (
        <label htmlFor={componentId}>
          <span className={`${formControlNamespace}__label`}>{label}</span>
        </label>
      )}
      <div className={splitControlClassNames}>
        {/* @ts-expect-error srLabel and label can't be undef,cause we're handling it with TS and with a checkProp */}
        {splitPosition === 'right' && <TextField {...fieldProps} split />}
        <DropdownStandalone
          className={splitButtonClassNames}
          label={srLabel || label}
          menuAlignment="bottom"
          defaultValue={getDefaultValue()}
          onOpen={onDropdownOpen}
          disabled={disabled || isReadonly}
          id={`${componentId}-dropdown`}
          renderCustomTrigger={renderCustomTrigger}
          onChange={customOnChange}
        >
          {/* @ts-expect-error list should be required on next major, since this comp has no sense without options */}
          {list?.content.map((item) => /** @type {React.ReactElement} */ ((
            <DropdownItem
              value={(item.title)}
              className={splitItemClassNames}
              key={transformToKebabCase(item.title)}
              title={item.title}
              leftContent={item.icon && <item.icon />}
            />
          )))}
        </DropdownStandalone>
        {/* @ts-expect-error srLabel and label can't be undef,cause we're handling it with TS and with a checkProp */}
        {splitPosition === 'left' && <TextField {...fieldProps} split />}
      </div>
      {helper && !disabled && !isReadonly && (
        <div className={`${formControlNamespace}__bottom`}>
          <Helper
            id={`${componentId}-message`}
            modifier={computeModifier(modifier)}
            // @ts-expect-error: Internal prop
            andesDataAttributes={{ 'data-andes-split-textfield-helper': true }}
          >
            {helper}
          </Helper>
        </div>
      )}
    </div>
  );
};

SplitTextfield.displayName = 'SplitTextfield';

SplitTextfield.propTypes = {
  autoFocus: PropTypes.bool,
  children: checkChildrenProp,
  className: PropTypes.string,
  defaultSelection: PropTypes.number,
  defaultValue: PropTypes.string,
  disabled: PropTypes.bool,
  helper: PropTypes.oneOfType([PropTypes.string, PropTypes.node]),
  id: PropTypes.string,
  inputProps: PropTypes.shape({}),
  label: checkLabelProp,
  list: PropTypes.shape({
    onClick: PropTypes.func,
    content: PropTypes.arrayOf(
      PropTypes.shape({
        title: PropTypes.string,
        icon: PropTypes.func,
      }),
    ),
  }),
  modifier: PropTypes.oneOf(['error', 'readonly', 'indeterminate', 'completed']),
  onBlur: PropTypes.func,
  onChange: PropTypes.func,
  onDropdownOpen: PropTypes.func,
  onFocus: PropTypes.func,
  placeholder: PropTypes.string,
  splitIcon: PropTypes.oneOfType([
    PropTypes.node,
    PropTypes.shape({
      title: PropTypes.string,
      src: PropTypes.string,
      alt: PropTypes.string,
      src2x: PropTypes.string,
    }),
  ]),
  splitLabel: PropTypes.oneOfType([PropTypes.node, PropTypes.string]),
  splitPosition: PropTypes.oneOf(['left', 'right']),
  srLabel: checkLabelProp,
  value: PropTypes.oneOfType([PropTypes.number, PropTypes.string]),
};

export default SplitTextfield;
