import React from 'react';
import PropTypes from 'prop-types';
import useSrLabel from '@andes/common/build/hooks/useSrLabel';
import { VisuallyHidden } from '@andes/visually-hidden';
import FeedbackPositive12 from '@andes/icons/FeedbackPositive12';
import FeedbackPositive20 from '@andes/icons/FeedbackPositive20';
import { formControlNamespace } from '../constants';

/**
 * @typedef {Object} ValidatedIconProps
 * @prop {string} notificationsLabel
 * @prop {string} [size]
 */

/** @type {React.FunctionComponent<ValidatedIconProps>} */
const ValidatedIcon = ({ notificationsLabel, size = 'large' }) => {
  const srLabelVisibility = useSrLabel();

  return (
    <span role="status" aria-live="polite">
      <VisuallyHidden>
        {srLabelVisibility && notificationsLabel}
      </VisuallyHidden>
      <span className={`${formControlNamespace}__validated-icon`}>
        {size === 'large' ? <FeedbackPositive20 color="currentColor" /> : <FeedbackPositive12 color="currentColor" />}

      </span>
    </span>
  );
};

ValidatedIcon.propTypes = {
  notificationsLabel: PropTypes.string.isRequired,
  size: PropTypes.string,
};

export default ValidatedIcon;
