import React from 'react';
import PropTypes from 'prop-types';
import classNames from 'classnames';
import { i18NPropTypeChecker } from '@andes/common/build/utils/propTypesValidators';
import { FocusRing } from '@react-aria/focus';
import handlers from '../scripts/handlers';
import { checkLabelProp } from '../constants/warnings/shared';
import VisibilityON20 from '@andes/icons/VisibilityON20';
import VisibilityOFF20 from '@andes/icons/VisibilityOFF20';
import { Helper } from '@andes/form';

const namespace = 'andes-form-control';

const iconAttributes = {
  color: 'currentColor',
};

/** @typedef {import('@meli/i18n').I18n} I18n */

/**
 * @typedef PasswordState
 * @prop {boolean} focused
 * @prop {boolean} showPassword
 */

/** @typedef {import('../..').PasswordProps} PasswordPublicProps */

/**
 * @typedef {Object} PasswordInternalProps
 * @prop {React.RefObject<HTMLDivElement | null> | ((refElement: HTMLDivElement | null) => void)} [innerRef]
 * @prop {import('@meli/i18n').I18n} i18n
 * @prop {Record<string, unknown>} [andesDataAttributes]
 */

/** @typedef {PasswordPublicProps & PasswordInternalProps} PasswordProps */


/** @extends {React.Component<PasswordProps, PasswordState>} */
class Password extends React.Component {
  /** @param {PasswordProps} props */
  constructor(props) {
    super(props);

    /** @type {PasswordState} */
    this.state = {
      focused: props.autoFocus || false,
      showPassword: false,
    };

    this.isUncontrolledValue = props.value === undefined;

    this.setField = this.setField.bind(this);
    this.setContainer = this.setContainer.bind(this);
    this.onBlurHandler = this.onBlurHandler.bind(this);
    this.onFocusHandler = this.onFocusHandler.bind(this);
    this.onChangeHandler = this.onChangeHandler.bind(this);
    this.onChangeIconHandler = this.onChangeIconHandler.bind(this);
    this.renderShowHidePasswordButton = this.renderShowHidePasswordButton.bind(this);
    this.setHiddenPass = this.setHiddenPass.bind(this);
  }

  /** @param {React.FocusEvent<HTMLInputElement>} event */
  onBlurHandler(event) {
    const { container, field } = this;
    const { value } = /** @type {HTMLInputElement} */(field);

    const { onBlur } = this.props;

    handlers.onBlur(container, value);
    this.setState({ focused: false });

    if (onBlur) onBlur(event);
  }

  /** @param {React.FocusEvent<HTMLInputElement>} event */
  onFocusHandler(event) {
    const { container } = this;
    const { onFocus } = this.props;

    handlers.onFocus(container);
    this.setState({ focused: true });

    if (onFocus) onFocus(event);
  }

  /** @param {React.ChangeEvent<HTMLInputElement>} event */
  onChangeHandler(event) {
    const { target: { value } } = event;
    const { showHide = false, onChange } = this.props;
    const { hiddenPass } = this;

    if (showHide && this.isUncontrolledValue) handlers.onChange(value, hiddenPass);
    if (onChange) onChange(event);
  }

  onChangeIconHandler() {
    const { onClickShowPassword } = this.props;
    this.setState((prevState) => ({
      ...prevState,
      showPassword: !prevState.showPassword,
    }));
    if (onClickShowPassword) onClickShowPassword();
  }

  /** @param {HTMLInputElement} fieldRef */
  setField(fieldRef) {
    this.field = fieldRef;
  }

  /** @param {HTMLDivElement} containerRef */
  setContainer(containerRef) {
    const { innerRef } = this.props;
    this.container = containerRef;
    if (innerRef) /** @type {React.RefObject<HTMLDivElement | null>} */(innerRef).current = containerRef;
  }

  /** @param {HTMLInputElement} passRef */
  setHiddenPass(passRef) {
    this.hiddenPass = passRef;
  }

  /** @param {I18n} i18n */
  renderShowHidePasswordButton(i18n) {
    const { id } = this.props;
    const { showPassword } = this.state;

    return (
      <div className={`${namespace}__password-embedded`}>
        <input
          checked={showPassword}
          className={`${namespace}__password-checkbox`}
          id={`${id}-checkbox`}
          type="checkbox"
          onChange={this.onChangeIconHandler}
          aria-label={i18n.pgettext('andes-textfield', 'Mostrar contraseña')}
        />
        <div className={`${namespace}__password-icon`}>
          {showPassword ? <VisibilityON20 {...iconAttributes} /> : <VisibilityOFF20 {...iconAttributes} />}
        </div>
      </div>
    );
  }

  render() {
    const {
      autoFocus = false,
      className,
      defaultValue,
      helper,
      i18n,
      id,
      innerRef,
      inputProps = {},
      label,
      maxLength = 120,
      modifier,
      onClickShowPassword,
      showHide = false,
      srLabel,
      value,
      andesDataAttributes,
      ...other
    } = this.props;

    const { focused, showPassword } = this.state;

    const fieldProps = {
      ...other,
      ...inputProps,
      'aria-describedby': helper ? `${id}-message` : undefined,
      'aria-invalid': modifier === 'error',
      'aria-label': srLabel,
      autoFocus,
      className: `${namespace}__field`,
      id,
      // eslint-disable-next-line object-shorthand
      maxLength: /** @type {number} */(maxLength),
      onBlur: this.onBlurHandler,
      onChange: this.onChangeHandler,
      onFocus: this.onFocusHandler,
      ref: this.setField,
      type: showPassword ? 'text' : 'password',
      value,
      defaultValue,
      autoComplete: inputProps.autoComplete || 'current-password',
    };

    const fieldHiddenProps = {
      style: { display: 'none' },
      type: 'password',
      id: 'password-hidden',
      value,
      defaultValue,
      ref: this.setHiddenPass,
      autoComplete: inputProps.autoComplete || 'current-password',
    };

    const classes = classNames(namespace, className, `${namespace}--textfield`, {
      [`${namespace}--password`]: showHide,
      [`${namespace}--focused`]: autoFocus,
      [`${namespace}--${modifier}`]: modifier,
    });

    return (
      <div className={classes} ref={this.setContainer} data-andes-password {...andesDataAttributes}>
        {label && <label htmlFor={id} className={`${namespace}__label`}>{label}</label>}
        <FocusRing within isTextInput focusRingClass={focused ? 'visible-focused' : ''}>
          <div className={`${namespace}__control`}>
            <input key="field" {...fieldProps} data-andes-password-input />
            <input key="field-password-hidden" {...fieldHiddenProps} />

            {showHide && this.renderShowHidePasswordButton(i18n)}
          </div>
        </FocusRing>
        {(helper || showHide) && (
        <div className={`${namespace}__bottom`}>
          <Helper
            id={`${id}-message`}
            modifier={(modifier === 'error') ? modifier : undefined}
            // @ts-expect-error: Internal prop
            andesDataAttributes={{ 'data-andes-password-helper': true }}
          >
            {helper}
          </Helper>
        </div>
        )}
      </div>
    );
  }
}

Password.propTypes = {
  autoFocus: PropTypes.bool,
  className: PropTypes.string,
  defaultValue: PropTypes.oneOfType([PropTypes.number, PropTypes.string]),
  helper: PropTypes.oneOfType([PropTypes.node, PropTypes.string]),
  id: PropTypes.string,
  innerRef: PropTypes.shape({
    current: PropTypes.oneOfType([PropTypes.node, PropTypes.object]),
  }),
  inputProps: PropTypes.shape({}),
  i18n: i18NPropTypeChecker,
  label: checkLabelProp,
  maxLength: PropTypes.oneOfType([PropTypes.number, PropTypes.string]),
  modifier: PropTypes.oneOf(['indeterminate', 'completed', 'error']),
  onBlur: PropTypes.func,
  onChange: PropTypes.func,
  onClickShowPassword: PropTypes.func,
  onFocus: PropTypes.func,
  placeholder: PropTypes.string,
  showHide: PropTypes.bool,
  srLabel: checkLabelProp,
  value: PropTypes.oneOfType([PropTypes.number, PropTypes.string]),
};

export default Password;
