import React, { useState, useEffect, useRef } from 'react';
import PropTypes from 'prop-types';
import classNames from 'classnames';
import { useFocusRing } from '@react-aria/focus';
import { useId, useAndesContext } from '@andes/context';
import enTranslations from '../../translations/en/messages.json';
import zhCnTranslations from '../../translations/zh-CN/messages.json';
import esArTranslations from '../../translations/es-AR/messages.json';
import ptBrTranslations from '../../translations/pt-BR/messages.json';
import { BACKSPACE, TAB, KEY_V } from '@andes/common/build/constants/keyboardCodes';
import { autofocus as inputAutoFocus } from '@andes/common/build/utils/autofocus';
import { isWebView } from '@andes/common/build/webkit/utils';
import { hasTouchSupport } from '@andes/common/build/utils/isMobile';
import includes from '@andes/common/build/utils/includes';
import ValidatedIcon from './ValidatedIcon';
import { checkLabelProp } from '../constants/warnings/shared';
import { Helper } from '@andes/form';

const numericNamespace = 'andes-form-control--numeric';
const namespace = 'andes-form-control';
const translationsNamespace = 'andes-textfield';

const onlyNumberRegex = /^[0-9]*$/;
const DEFAULT_FOCUS_INDEX = 0;
const NOT_FOCUSABLE_INDEX = -1;
const numbersRegex = /[^0-9]/gi;
const specialCharacters = [
  'Backspace',
  'Tab',
  'Enter',
  'Control',
  'Shift',
  'Escape',
  'Meta',
  'Alt',
  'CapsLock',
  'ArrowLeft',
  'ArrowRight',
];

/** @typedef {import('../..').NumericProps} NumericPublicProps */

/** @param {boolean | number} focus */
const getFocusIndexOrFalsy = (focus) =>
  (focus === false ? NOT_FOCUSABLE_INDEX : Number(focus === true ? DEFAULT_FOCUS_INDEX : focus));

/**
 * @param {number} digits
 * @returns {string[]}
 */
const getDefaultValue = (digits) => {
  if (!digits || typeof digits !== 'number') return [];
  return new Array(digits).fill('');
};

/** @param {string | string []} value */
const isEmpty = (value) => {
  const array = typeof value === 'string' ? value.split('') : value;

  return array.every((item) => !item);
};

/**
 * @param {string | Array<string>} [value]
 * @param {number} [digits]
 * @returns {Array<string> | undefined}
 */
const parsedValues = (value, digits) => {
  if (typeof value === 'string') {
    let parsedValue = value.replace(numbersRegex, '').split('');

    if (digits && parsedValue.length < digits) {
      const diff = digits - parsedValue.length;
      const arrayEmpty = new Array(diff).fill('');
      parsedValue = parsedValue.concat(arrayEmpty);
    }

    return parsedValue;
  }

  if (Array.isArray(value)) return value;
};

/**
 * @typedef {Object} NumericInternalProps
 * @prop {Record<string, unknown>} [andesDataAttributes]
 */

/**
 * @typedef {NumericPublicProps & NumericInternalProps} NumericProps
 */

/** @type {React.FunctionComponent<NumericProps>} */
const Numeric = ({
  centered = false,
  className,
  defaultValue,
  digits = 1,
  disabled = false,
  focus = DEFAULT_FOCUS_INDEX,
  helper,
  id,
  label,
  modifier,
  onChange,
  onPaste,
  srLabel,
  strict = false,
  value,
  ref,
  andesDataAttributes,
}) => {
  const [inputValue, setInputValue] = useState(/** @type {Array<string>} */ (
    parsedValues(defaultValue, digits) || getDefaultValue(digits)
  ));
  const [focusedItem, setFocusedItem] = useState(getFocusIndexOrFalsy(focus));
  const { current: isControlled } = useRef(typeof value !== 'undefined');
  const currentValue = isControlled ? (parsedValues(value, digits) || []) : inputValue;

  /** @type {React.RefObject<Array<HTMLInputElement | null> | []>} */
  const inputsRef = useRef([]);
  const firstRender = useRef(true);
  const { isFocusVisible, focusProps } = useFocusRing();
  const { i18n, device } = useAndesContext('@andes/textfield',
    { en: enTranslations, 'es-AR': esArTranslations, 'pt-BR': ptBrTranslations, 'zh-CN': zhCnTranslations });
  const isMobile = device?.mobile;

  const componentId = useId(id);


  /**
   * @param {React.KeyboardEvent<HTMLInputElement>} event
   * @param {number} index
   * */
  const moveFocusBackwards = (event, index) => {
    const newIndex = index - 1;
    const newValue = [...currentValue];

    if (newIndex >= 0) newValue[newIndex] = '';
    setFocusedItem((state) => (newIndex > -1 ? newIndex : state));

    if (!isControlled) {
      setInputValue(newValue);
    }

    if (typeof onChange === 'function') {
      onChange(/** @type {React.ChangeEvent<HTMLInputElement>} */ (/** @type {unknown} */ (event)), newValue);
    }
  };

  const moveFocusForward = () => {
    setFocusedItem((state) => {
      const newIndex = state + 1;
      return newIndex < digits ? newIndex : state;
    });
  };

  /**
   * @param {React.FormEvent<HTMLInputElement> | React.ChangeEvent<HTMLInputElement>} event
   * @param {string | string[]} values
   */
  const assignPastedValues = (event, values) => {
    const newValues = currentValue;
    const newFocus = values.length > digits ? digits - 1 : values.length - 1;
    for (let i = 0; i < currentValue.length; i += 1) {
      newValues[i] = values[i] ?? '';
    }

    setInputValue(newValues);
    setFocusedItem(newFocus);

    if (typeof onPaste === 'function') onPaste(/** @type {React.ClipboardEvent<HTMLInputElement>} */(event), newValues);
  };

  /** @param {React.ClipboardEvent<HTMLInputElement>} event */
  const handlePaste = (event) => {
    const textPlainItems = Array.from(event?.clipboardData?.items || []).filter(
      (item) => item.type === 'text/plain' || item.type === 'text',
    );

    if (textPlainItems.length > 0) {
      textPlainItems[0]?.getAsString((text) => {
        const pastedValues = text.replace(numbersRegex, '').split('');
        assignPastedValues(event, pastedValues);
      });
    }
  };

  /** @param {React.FormEvent<HTMLInputElement>} event */
  const onInputHandler = (event) => {
    const { target: { value: eventValue } } = /** @type {React.ChangeEvent<HTMLInputElement>} */(event);

    if (eventValue?.length === digits) {
      setFocusedItem(digits - 1);
      return;
    }

    if (!onlyNumberRegex.test(eventValue) || (eventValue.length > 1 && eventValue.length !== digits)) {
      return;
    }

    if (eventValue?.trim() !== '') {
      moveFocusForward();
    }
  };

  /**
   * @param {React.ChangeEvent<HTMLInputElement>} event
   * @param {number} index
   */
  const onChangeHandler = (event, index) => {
    const { target: { value: eventValue } } = event;

    if (!onlyNumberRegex.test(eventValue) || (eventValue.length > 1 && eventValue.length !== digits)) {
      return;
    }

    const newValue = [...currentValue];

    if (eventValue.length === digits) {
      const values = eventValue.split('');
      for (let i = 0; i < currentValue.length; i += 1) {
        newValue[i] = values[i] ?? '';
      }
    } else {
      newValue[index] = eventValue;
    }


    if (!isControlled) {
      setInputValue(newValue);
    }

    if (typeof onChange === 'function') {
      onChange(event, newValue);
    }

    return /** @type {string | string[]} */ (newValue);
  };

  /**
   * @param {React.KeyboardEvent<HTMLInputElement>} event
   * @param {number} index
   */
  const onKeyDownHandler = (event, index) => {
    const eventValue = /** @type {HTMLInputElement} */ (event.target).value;
    if (event.code === BACKSPACE || event.key === 'Backspace') {
      if (eventValue === '') {
        moveFocusBackwards(event, index);
        return;
      }
    }

    if (event.code === TAB || event.key === 'Tab') {
      if (index === digits - 1 || index === 0) {
        setFocusedItem(NOT_FOCUSABLE_INDEX);
        return;
      }
    }

    const isPasting = (event.metaKey || event.ctrlKey) && event.code === KEY_V;

    if (isPasting) return;

    if (includes(specialCharacters, event.key)) return;

    const isInvalid = event.key.match(numbersRegex);

    if (isInvalid) {
      event.preventDefault();
    }
  };

  /** @param {number} index */
  const focusValidItem = (index) => {
    const item = inputsRef.current[index];
    if (item) {
      if (!firstRender.current) {
        item.focus();
      } else {
        inputAutoFocus(item, firstRender.current);
        firstRender.current = false;
      }
    }
  };

  /** @param {React.MouseEvent<HTMLInputElement>} event */
  const onClickHandler = (event) => {
    if (isEmpty(currentValue) && (isWebView() || (!hasTouchSupport() && !isMobile))) {
      event.preventDefault();
      if (focusedItem === DEFAULT_FOCUS_INDEX) {
        focusValidItem(DEFAULT_FOCUS_INDEX);
      } else {
        setFocusedItem(DEFAULT_FOCUS_INDEX);
      }
    }
  };

  /**
   * @param {React.FocusEvent<HTMLInputElement>} event
   * @param {number} index
   */
  const onFocusHandler = (event, index) => {
    setFocusedItem(index);

    if (typeof focusProps.onFocus === 'function') focusProps.onFocus(event);
  };

  /** @param {React.FocusEvent<HTMLInputElement>} event */
  const handleBlur = (event) => {
    setFocusedItem(NOT_FOCUSABLE_INDEX);

    if (typeof focusProps.onBlur === 'function') focusProps.onBlur(event);
  };

  useEffect(() => {
    if (focusedItem !== NOT_FOCUSABLE_INDEX) {
      focusValidItem(focusedItem);
    }
  // eslint-disable-next-line react-hooks/exhaustive-deps
  }, [focusedItem]);

  const containerClassNames = classNames(numericNamespace, className, {
    [`${namespace}--${modifier}`]: modifier,
    [`${namespace}--centered`]: centered,
  });

  return (
    <div
      className={containerClassNames}
      role="group"
      aria-label={srLabel}
      aria-labelledby={label ? `${componentId}-label` : undefined}
      aria-describedby={helper ? `${componentId}-message` : undefined}
      onPaste={handlePaste}
      ref={ref}
      {...andesDataAttributes}
    >
      {label && <span id={`${componentId}-label`} className={`${namespace}__label`} data-andes-codeinput-label>{label}</span>}
      <div className={`${numericNamespace}-wrapper`}>
        {
          [...Array(digits)].map((_, index) => {
            const textFieldPadding = classNames(`${namespace}__textfield-space`, {
              [`${namespace}__textfield-space--big`]: (digits === 6) && (index === 2),
            });

            const inputWrapperClasses = classNames(namespace, `${namespace}--textfield`, {
              [`${namespace}--centered`]: centered,
              [`${namespace}--focused`]: focusedItem === index,
              [`${namespace}--visible-focused`]: isFocusVisible && focusedItem === index,
              [`${namespace}--${modifier}`]: modifier,
              [`${namespace}--disabled`]: disabled,
            });

            return (
              <div className={textFieldPadding} key={`${componentId}-${index}`}>
                <div className={inputWrapperClasses}>
                  <div className={`${namespace}__control`}>
                    <input
                      className={`${namespace}__field`}
                      aria-label={i18n.pgettext(translationsNamespace, 'Dígito {0}', index + 1)}
                      type={strict ? 'tel' : 'number'}
                      pattern="[0-9]*"
                      value={currentValue[index]}
                      id={`${componentId}-digit-${index}`}
                      onChange={(evt) => onChangeHandler(evt, index)}
                      onInput={onInputHandler}
                      onKeyDown={(evt) => onKeyDownHandler(evt, index)}
                      onFocus={(evt) => onFocusHandler(evt, index)}
                      onBlur={handleBlur}
                      onMouseDown={onClickHandler}
                      disabled={disabled}
                      ref={(el) => { inputsRef.current[index] = el; }}
                      aria-invalid={modifier === 'error'}
                      {...index === 0 && { autoComplete: 'one-time-code', autoFocus: focus !== false }}
                      data-andes-codeinput-input
                    />
                    {modifier === 'completed' && (
                      <ValidatedIcon
                        notificationsLabel={i18n.pgettext(translationsNamespace, 'Campo de texto valido')}
                      />
                    )}
                  </div>
                </div>
              </div>
            );
          })
        }
      </div>
      {helper && (
        <div className={`${namespace}__bottom`}>
          <Helper
            id={`${id}-message`}
            modifier={(modifier === 'error') ? modifier : undefined}
            // @ts-expect-error: Internal prop
            andesDataAttributes={{ 'data-andes-codeinput-helper': true }}
          >
            {helper}
          </Helper>
        </div>
      )}
    </div>
  );
};

Numeric.displayName = 'Numeric';

Numeric.propTypes = {
  centered: PropTypes.bool,
  className: PropTypes.string,
  defaultValue: PropTypes.oneOfType([
    PropTypes.arrayOf(PropTypes.string),
    PropTypes.string,
  ]),
  digits: PropTypes.number,
  disabled: PropTypes.bool,
  focus: PropTypes.oneOfType([PropTypes.bool, PropTypes.number]),
  helper: PropTypes.oneOfType([PropTypes.string, PropTypes.node]),
  id: PropTypes.string,
  label: checkLabelProp,
  modifier: PropTypes.oneOf(['completed', 'error']),
  onChange: PropTypes.func,
  onPaste: PropTypes.func,
  srLabel: checkLabelProp,
  strict: PropTypes.bool,
  value: PropTypes.oneOfType([
    PropTypes.arrayOf(PropTypes.string),
    PropTypes.string,
  ]),
  andesDataAttributes: PropTypes.shape({}),
};

export default Numeric;
