/**
 * @typedef {Object} LabelDataset
 * @prop {string} showLabel
 * @prop {string} hideLabel
 * @prop {string} show
 */

export default {
  /**
   * @param {HTMLDivElement | undefined | null} element
   */
  onFocus: function onFocus(element) {
    element?.classList.add('andes-form-control--focused');
  },
  /**
   * @param {HTMLElement | undefined | null} element
   * @param {string} value
   */
  onBlur: function onBlur(element, value) {
    element?.classList.remove('andes-form-control--focused');
    if (value && value.length) {
      element?.classList.add('andes-form-control--floated');
    } else {
      element?.classList.remove('andes-form-control--floated');
    }
  },

  /**
   * @param {string} value
   * @param {HTMLInputElement | undefined} inputHiddenRef
   */
  onChange: function onChange(value, inputHiddenRef) {
    if (inputHiddenRef) {
      inputHiddenRef.value = value;
    }
  },
};
